void Trie::insert(string word) {
    TrieNode* current = root;
    for (char ch : word) {
        int i = ch - 'a';
        if (!current->child[i]) current->child[i] = new TrieNode(ch);
        current = current->child[i];
    }
    current->endOfWord = true;
}
